{
 "level": "A1–B2",
 "intro": "In this topic you will learn <strong>word order</strong> in English: from the basic S–V–O structure to inversion and amplification.",
 "rules": [
 {
 "label": "Basic structure",
 "color": "emerald",
 "text": "<strong>Subject + Verb + Object</strong> — the basis of an English sentence:",
 "example": "She reads books."
 },
 {
 "label": "Question",
 "color": "blue",
 "text": "Auxiliary verb <strong>before</strong> the subject:",
 "example": "Do you like pizza?"
 },
 {
 "label": "Negation",
 "color": "rose",
 "text": "We add <strong>not</strong> after the auxiliary verb:",
 "example": "I don't like apples."
 }
 ]
}
